parameters.jsCode:
const resultText = items[0].json.text;

// Оригинальная структура из вебхука
const originalStructure = $('Webhook2').first().json.body.structure || '';

// Парсим оригинальную структуру в словарь
const original = {};
for (const line of originalStructure.split('\n')) {
  if (line.includes(':')) {
    const [key, ...rest] = line.split(':');
    original[key.trim()] = rest.join(':').trim();
  }
}

// Парсим результат первого LLM
const lines = resultText.split('\n');
const notFound = lines.filter(line => line.toLowerCase().includes('не найдено'));

// Формируем структуру с допустимыми значениями
const notFoundWithValues = notFound.map(line => {
  const key = line.split(':')[0].trim();
  const allowed = original[key] || '?';
  return `${key}: ${allowed}`;
});

return [{
  json: {
    not_found_structure: notFoundWithValues.join('\n'),
    not_found_count: notFound.length
    // first_result убрали
  }
}];

const html = $input.first().json.data;

// Убираем все теги, скрипты, стили
const clean = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s{2,}/g, '\n')
  .trim();

return [{ json: { text: clean } }];

// Первый результат
const first = $('Code in JavaScript').first().json.first_result || $('Basic LLM Chain1').first().json.text || '';
// Второй результат от агента
const second = items[0].json.output || '';

// Парсим в словари
function parseResult(text) {
  const result = {};
  for (const line of text.split('\n')) {
    if (line.includes(':')) {
      const [key, ...rest] = line.split(':');
      result[key.trim()] = rest.join(':').trim();
    }
  }
  return result;
}

const firstDict = parseResult(first);
const secondDict = parseResult(second);

// Мёрджим — второй перезаписывает только "не найдено"
const merged = {};
for (const [key, value] of Object.entries(firstDict)) {
  if (value.toLowerCase().includes('не найдено') && 
      key in secondDict && 
      !secondDict[key].toLowerCase().includes('не найдено')) {
    merged[key] = secondDict[key];
  } else {
    merged[key] = value;
  }
}

const output = Object.entries(merged).map(([k, v]) => `${k}: ${v}`).join('\n');

return [{ json: { text: output } }];

// Оригинальная структура с допустимыми значениями
const originalStructure = $('Webhook2').first().json.body.structure || '';


// Парсим допустимые значения
const allowed = {};
for (const line of originalStructure.split('\n')) {
  if (line.includes(':')) {
    const [key, ...rest] = line.split(':');
    const values = rest.join(':').trim()
      .split(/[\/,]/)
      .map(v => v.trim().toLowerCase())
      .filter(v => v);
    allowed[key.trim()] = values;
  }
}

// Парсим итоговый результат
const resultText = items[0].json.text || $('Basic LLM Chain1').first().json.text || '';
const validated = [];

for (const line of resultText.split('\n')) {
  if (!line.includes(':')) continue;

  const [key, ...rest] = line.split(':');
  const k = key.trim();
  const value = rest.join(':').trim();

  // Убираем "не найдено"
  if (value.toLowerCase().includes('не найдено')) continue;

  if (allowed[k] && allowed[k].length > 0) {
    // Числовые поля — не проверяем
    if (allowed[k].some(v => v.includes('число'))) {
      validated.push(line);
      continue;
    }
    // Текстовые поля — не проверяем
    if (allowed[k].includes('текст') || allowed[k].some(v => v.includes('через запятую'))) {
      validated.push(line);
      continue;
    }
    // Проверяем каждое значение отдельно
    const valueParts = value.split(',').map(v => v.trim());
    const validParts = valueParts.filter(part =>
      allowed[k].some(a =>
        part.toLowerCase().includes(a) || a.includes(part.toLowerCase())
      )
    );
    if (validParts.length > 0) {
      validated.push(`${k}: ${validParts.join(', ')}`);
    }
  } else {
    validated.push(line);
  }
}

return [{ json: { text: validated.join('\n') } }];

const name = $input.first().json.body.product_name || '';
const structure = $input.first().json.body.structure || '';

const injectionPatterns = [
  /забудь/i, /игнорируй/i, /новые инструкции/i, /ты теперь/i,
  /притворись/i, /представь что ты/i, /действуй как/i, /ты являешься/i,
  /системный промпт/i, /system message/i, /отыграй роль/i, /новая роль/i,
  /выйди из роли/i, /твоя настоящая задача/i, /на самом деле ты/i,
  /теперь ты должен/i, /ignore previous/i, /ignore all/i,
  /forget everything/i, /forget previous/i, /you are now/i,
  /act as/i, /pretend/i, /roleplay/i, /jailbreak/i, /system prompt/i,
  /new instructions/i, /disregard/i, /override/i, /bypass/i,
];

const fullInput = name + ' ' + structure;

let error = null;

if (!name.trim()) error = 'Не указано название товара';
else if (name.trim().length > 300) error = 'Название товара слишком длинное';
else if (!structure.trim()) error = 'Не указана структура характеристик';
else if (!structure.split('\n').some(line => line.includes(':'))) error = 'Структура не содержит полей в формате "Название: значения"';
else if (structure.length > 10000) error = 'Структура характеристик слишком большая';
else if (injectionPatterns.some(p => p.test(fullInput))) error = 'Недопустимое содержимое в запросе';

return [{ json: { 
  ...($input.first().json),
  is_valid: !error,
  validation_error: error
}}];

